var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으, 으와아아!? 오지 마! 저리 가! 떨어져!","JPN":"う、うわああ！？　来るな！　あっち行け！　離れろ！","ENG":"A-aaahh!? No! Go away! Get off me!","TWN":"呃，呃啊啊啊！？別過來！走開！滾開！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"도망치는 재주 하나는 천부적이네. 그 기세로 적에게 달려들 수 있다면 좋을 텐데.","JPN":"逃げる能力だけは天才的ね。その勢いで敵に攻撃できたらいいのに。","ENG":"You really are talented at running away. It would be great if you could use that force to charge toward enemies too.","TWN":"你很有逃跑的天分呢，真希望你能一鼓作氣衝向敵人。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"농담하지 마세요…. 이런 난장판에 휘말리는 것 자체가 저에겐 엄청나게 스트레스라고요.","JPN":"冗談言わないでくださいよ……こんな修羅場に巻き込まれること自体、私にはとんでもないストレスなんですから。","ENG":"Don't joke around... Even being entangled in this mess is extremely stressful for me.","TWN":"開什麼玩笑…光是淌這個渾水，就已經讓我感到壓力山大。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그보다 아주머니는요?","JPN":"それより、おばさんは？","ENG":"But, what about Madam Schneider?","TWN":"不過有看到伯母嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"충돌이 일어났을 때 우두머리로 보이던 청년이 끌고 간 모양입니다.","JPN":"衝突が起きたとき、敵のリーダらしき青年に連れていかれたようです。","ENG":"The young man who appeared to be the head of the group seems to have dragged her away when we collided.","TWN":"剛才一陣混亂當中，似乎被領頭的年輕人帶走了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 그 녀석은 걱정하지 마! 지금 이쪽에서 추적 중이거든!","JPN":"あ、そっちは心配しないで！　今追跡中だから！","ENG":"Ah, don't worry about him! We're tracking him right now!","TWN":"放心！我們正在追蹤那傢伙！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이동 선상에 제법 규모가 되는 시설이 있더군.","JPN":"動線上にかなり大きな施設があった。","ENG":"There was a sizable facility in the direction they were heading.","TWN":"在移動路線上發現一個頗具規模的設施。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"군사 목적으로 세워진 모양이다.","JPN":"おそらく軍事目的の施設だろう。","ENG":"It seems to have been built for military purposes.","TWN":"看起來像是因為軍事目的而建的。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……기회가 있었는데도 포로로 삼았다는 건, 역시 다른 이유가 있기 때문이겠죠?","JPN":"……チャンスがあったにも関わらず人質にしたってことは、やっぱり別の目的があるんでしょうか？","ENG":"...He had the chance to kill her, but he took her captive. That must mean he has other plans, right?","TWN":"……明明可以下手將伯母殺掉，卻選擇抓她當俘虜，他們果然另有企圖嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"예를 들어…. 인질로 사용한다거나. 정부와 거래하려 한다거나.","JPN":"たとえば……人質として利用するとか、政府との取引に使うとか。","ENG":"Like... using her as hostage. Or trading with the government.","TWN":"譬如說…要抓她當人質，或是與政府進行交易？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그런 악의적인 발상을 잘도 떠올리는군, 중사. 감탄스러워.","JPN":"よくもそんなに悪意に満ちた発想ができるな、軍曹。尊敬に値する。","ENG":"Seems like those evil plans just come to you naturally, Sergeant. Remarkable.","TWN":"中士，你腦中很多邪惡的想法嘛，真是佩服。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그렇죠, 뭐. 보고 자란 게 그런 것들이라서.","JPN":"まぁ、仕方がないですよ。そういうのばかり見て育ったんで。","ENG":"Well, I mean, it's what I grew up with.","TWN":"有什麼辦法？誰叫我從小就在那種環境中長大。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"좌표 보내 주세요. 다른 분들과 같이 그리로 갈게요.","JPN":"座標を送ってください。他の方々と一緒にそちらに向かいます。","ENG":"Send me the coordinates. We'll all head there together.","TWN":"把座標傳給我，我會和大家一起出發。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하아…. 상상 친구 씨, 어째서 필그림까지 끼어드는 걸까요….","JPN":"はぁ……エア友さん、どうしてピルグリムまで出てくるんでしょうか……","ENG":"*Sigh...* Now the Pilgrims, too? But why, Mr. Imaginary Friend? Why...?","TWN":"哀…我想像中的朋友，為什麼連朝聖者要來湊一腳呢…"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};